{
  "provider": "airtable",
  "apiHost": "api.airtable.com",
  "basePath": "/v0",
  "notes": "Airtable uses /v0 for record operations and /v0/meta for metadata operations. Webhook endpoints use /v0/bases. Enterprise endpoints use /v0/meta.",
  "scopeMap": [
    {
      "method": "GET",
      "pathPattern": "/v0/meta/whoami",
      "sufficientScopes": [],
      "description": "Get current user ID and granted scopes. No special scope required; user.email:read adds email to response."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/bases",
      "sufficientScopes": ["schema.bases:read"],
      "description": "List all accessible bases."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/bases",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Create a new base."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/bases/*/tables",
      "sufficientScopes": ["schema.bases:read"],
      "description": "Get base schema (list tables, fields, and views)."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/bases/*/tables",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Create a new table in a base."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/meta/bases/*/tables/*",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Update table name, description, or configuration."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/bases/*/tables/*/fields",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Create a new field in a table."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/meta/bases/*/tables/*/fields/*",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Update a field's name, description, or configuration."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/bases/*/views",
      "sufficientScopes": ["schema.bases:read"],
      "description": "List all views in a base."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/bases/*/views/*",
      "sufficientScopes": ["schema.bases:read"],
      "description": "Get a specific view."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/*/*",
      "sufficientScopes": ["data.records:read"],
      "description": "Get a single record by ID from a table."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/*",
      "sufficientScopes": ["data.records:read"],
      "description": "List records from a table (base ID and table name/ID in path)."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Create one or more records in a table."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Update records in a table (partial update)."
    },
    {
      "method": "PUT",
      "pathPattern": "/v0/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Replace records in a table (full update/upsert)."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Delete one or more records from a table."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/*/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Update a single record by ID."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/*/*",
      "sufficientScopes": ["data.records:write"],
      "description": "Delete a single record by ID."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/*/*/comments",
      "sufficientScopes": ["data.recordComments:read"],
      "description": "List comments on a specific record."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/*/*/comments",
      "sufficientScopes": ["data.recordComments:write"],
      "description": "Create a comment on a record."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/*/*/comments/*",
      "sufficientScopes": ["data.recordComments:write"],
      "description": "Update a comment on a record."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/*/*/comments/*",
      "sufficientScopes": ["data.recordComments:write"],
      "description": "Delete a comment from a record."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/bases/*/webhooks",
      "sufficientScopes": ["webhook:manage"],
      "description": "List all webhooks for a base."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/bases/*/webhooks",
      "sufficientScopes": ["webhook:manage"],
      "description": "Create a new webhook for a base."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/bases/*/webhooks/*",
      "sufficientScopes": ["webhook:manage"],
      "description": "Delete a webhook."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/bases/*/webhooks/*/refresh",
      "sufficientScopes": ["webhook:manage"],
      "description": "Refresh a webhook to extend its expiration (webhooks expire after 7 days)."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/bases/*/webhooks/*/payloads",
      "sufficientScopes": ["webhook:manage"],
      "description": "List payloads for a webhook."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/bases/*/collaborators",
      "sufficientScopes": ["schema.bases:read"],
      "description": "List collaborators on a base."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/bases/*/collaborators",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Add or update a collaborator on a base."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/meta/bases/*/collaborators/*",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Remove a collaborator from a base."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/workspaces/*/collaborators",
      "sufficientScopes": ["schema.bases:read"],
      "description": "List collaborators on a workspace."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/workspaces/*/collaborators",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Add or update a collaborator on a workspace."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/meta/workspaces/*/collaborators/*",
      "sufficientScopes": ["schema.bases:write"],
      "description": "Remove a collaborator from a workspace."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*/users",
      "sufficientScopes": ["enterprise.user:read"],
      "description": "List users in an enterprise account."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*/users/*",
      "sufficientScopes": ["enterprise.user:read"],
      "description": "Get information about a specific enterprise user."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/meta/enterpriseAccount/*/users/*",
      "sufficientScopes": ["enterprise.user:write"],
      "description": "Update an enterprise user (email, status, etc.)."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/meta/enterpriseAccount/*/users/*",
      "sufficientScopes": ["enterprise.user:write"],
      "description": "Deactivate or remove an enterprise user."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*/groups",
      "sufficientScopes": ["enterprise.groups:read"],
      "description": "List user groups in an enterprise account."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*/groups/*",
      "sufficientScopes": ["enterprise.groups:read"],
      "description": "Get a specific enterprise user group."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/enterpriseAccount/*/groups",
      "sufficientScopes": ["enterprise.groups:write"],
      "description": "Create a new enterprise user group."
    },
    {
      "method": "PATCH",
      "pathPattern": "/v0/meta/enterpriseAccount/*/groups/*",
      "sufficientScopes": ["enterprise.groups:write"],
      "description": "Update an enterprise user group."
    },
    {
      "method": "DELETE",
      "pathPattern": "/v0/meta/enterpriseAccount/*/groups/*",
      "sufficientScopes": ["enterprise.groups:write"],
      "description": "Delete an enterprise user group."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*",
      "sufficientScopes": ["enterprise.account:read"],
      "description": "Get enterprise account information."
    },
    {
      "method": "GET",
      "pathPattern": "/v0/meta/enterpriseAccount/*/auditLogs",
      "sufficientScopes": ["enterprise.changeEvents:read"],
      "description": "Retrieve enterprise audit log / change events."
    },
    {
      "method": "POST",
      "pathPattern": "/v0/meta/enterpriseAccount/*/auditLogs",
      "sufficientScopes": ["enterprise.changeEvents:read"],
      "description": "Create a new audit log export request."
    }
  ],
  "allScopes": [
    "data.records:read",
    "data.records:write",
    "data.recordComments:read",
    "data.recordComments:write",
    "schema.bases:read",
    "schema.bases:write",
    "webhook:manage",
    "block:manage",
    "user.email:read",
    "enterprise.user:read",
    "enterprise.user:write",
    "enterprise.account:read",
    "enterprise.groups:read",
    "enterprise.groups:write",
    "enterprise.changeEvents:read"
  ]
}

{
  "provider": "dropbox",
  "apiHost": "api.dropboxapi.com",
  "contentHost": "content.dropboxapi.com",
  "basePath": "/2",
  "notes": "Dropbox uses RPC-style API where ALL calls use POST. api.dropboxapi.com handles most endpoints; content.dropboxapi.com handles upload/download. Scopes sourced from the official dropbox-api-spec .stone files on GitHub.",
  "scopeMap": [
    {
      "method": "POST",
      "pathPattern": "/2/files/list_folder",
      "sufficientScopes": ["files.metadata.read"],
      "description": "List contents of a folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/list_folder/continue",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Continue listing folder contents using a cursor."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/list_folder/get_latest_cursor",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Get a cursor for the latest state of a folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/list_folder/longpoll",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Long-poll endpoint to wait for changes on an account."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_metadata",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Get metadata for a file or folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/search",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Search for files and folders (deprecated, use search:2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/search_v2",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Search for files and folders."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/search/continue_v2",
      "sufficientScopes": ["files.metadata.read"],
      "description": "Continue a search using a cursor."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/list_revisions",
      "sufficientScopes": ["files.metadata.read"],
      "description": "List revisions of a file."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/download",
      "sufficientScopes": ["files.content.read"],
      "description": "Download a file. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/download_zip",
      "sufficientScopes": ["files.content.read"],
      "description": "Download a folder as a zip file. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/export",
      "sufficientScopes": ["files.content.read"],
      "description": "Export a file (e.g., Google Docs to PDF). Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_preview",
      "sufficientScopes": ["files.content.read"],
      "description": "Get a preview for a file. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_thumbnail",
      "sufficientScopes": ["files.content.read"],
      "description": "Get a thumbnail for an image (deprecated, use get_thumbnail_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_thumbnail_v2",
      "sufficientScopes": ["files.content.read"],
      "description": "Get a thumbnail for an image. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_thumbnail_batch",
      "sufficientScopes": ["files.content.read"],
      "description": "Get thumbnails for a batch of images. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_temporary_link",
      "sufficientScopes": ["files.content.read"],
      "description": "Get a temporary direct link to a file."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload",
      "sufficientScopes": ["files.content.write"],
      "description": "Upload a file up to 150 MB. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/start",
      "sufficientScopes": ["files.content.write"],
      "description": "Start an upload session for large files. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/start_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Start a batch of upload sessions."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/append_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Append more data to an upload session. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/finish",
      "sufficientScopes": ["files.content.write"],
      "description": "Finish an upload session and save the file. Host: content.dropboxapi.com."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/finish_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Finish multiple upload sessions in one call (deprecated, use finish_batch_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/finish_batch_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Finish multiple upload sessions in one call."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/upload_session/finish_batch/check",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a batch upload finish job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/get_temporary_upload_link",
      "sufficientScopes": ["files.content.write"],
      "description": "Get a temporary upload link for a file."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/create_folder_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Create a folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/create_folder",
      "sufficientScopes": ["files.content.write"],
      "description": "Create a folder (deprecated, use create_folder_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/create_folder_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Create multiple folders at once."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/create_folder_batch/check",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a create folder batch job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/delete_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Delete a file or folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/delete",
      "sufficientScopes": ["files.content.write"],
      "description": "Delete a file or folder (deprecated, use delete_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/delete_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Delete multiple files or folders."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/delete_batch/check",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a delete batch job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/permanently_delete",
      "sufficientScopes": ["files.permanent_delete"],
      "description": "Permanently delete a file or folder (bypasses trash)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Copy a file or folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy",
      "sufficientScopes": ["files.content.write"],
      "description": "Copy a file or folder (deprecated, use copy_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_batch_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Copy multiple files or folders."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_batch/check_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a copy batch job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Copy multiple files or folders (deprecated)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_batch/check",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a copy batch job (deprecated)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_reference/get",
      "sufficientScopes": ["files.content.write"],
      "description": "Get a copy reference to a file or folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/copy_reference/save",
      "sufficientScopes": ["files.content.write"],
      "description": "Save a copy reference to the user's Dropbox."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Move a file or folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move",
      "sufficientScopes": ["files.content.write"],
      "description": "Move a file or folder (deprecated, use move_v2)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move_batch_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Move multiple files or folders."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move_batch/check_v2",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a move batch job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move_batch",
      "sufficientScopes": ["files.content.write"],
      "description": "Move multiple files or folders (deprecated)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/move_batch/check",
      "sufficientScopes": ["files.content.write"],
      "description": "Check status of a move batch job (deprecated)."
    },
    {
      "method": "POST",
      "pathPattern": "/2/files/restore",
      "sufficientScopes": ["files.content.write"],
      "description": "Restore a file to a specific revision."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/share_folder",
      "sufficientScopes": ["sharing.write"],
      "description": "Share a folder with collaborators."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/check_share_job_status",
      "sufficientScopes": ["sharing.write"],
      "description": "Check the status of an asynchronous share folder job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/check_job_status",
      "sufficientScopes": ["sharing.write"],
      "description": "Check the status of an asynchronous sharing job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_folders",
      "sufficientScopes": ["sharing.read"],
      "description": "List shared folders the user has access to."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_folders/continue",
      "sufficientScopes": ["sharing.read"],
      "description": "Continue listing shared folders using a cursor."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_mountable_folders",
      "sufficientScopes": ["sharing.read"],
      "description": "List shared folders the user can mount."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_mountable_folders/continue",
      "sufficientScopes": ["sharing.read"],
      "description": "Continue listing mountable shared folders."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/get_folder_metadata",
      "sufficientScopes": ["sharing.read"],
      "description": "Get metadata for a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_folder_members",
      "sufficientScopes": ["sharing.read"],
      "description": "List members of a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/list_folder_members/continue",
      "sufficientScopes": ["sharing.read"],
      "description": "Continue listing shared folder members."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/add_folder_member",
      "sufficientScopes": ["sharing.write"],
      "description": "Add a member to a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/remove_folder_member",
      "sufficientScopes": ["sharing.write"],
      "description": "Remove a member from a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/check_remove_member_job_status",
      "sufficientScopes": ["sharing.write"],
      "description": "Check status of a remove member job."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/update_folder_member",
      "sufficientScopes": ["sharing.write"],
      "description": "Update a shared folder member's access level."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/update_folder_policy",
      "sufficientScopes": ["sharing.write"],
      "description": "Update the sharing policy for a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/unshare_folder",
      "sufficientScopes": ["sharing.write"],
      "description": "Unshare a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/transfer_folder",
      "sufficientScopes": ["sharing.write"],
      "description": "Transfer ownership of a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/mount_folder",
      "sufficientScopes": ["sharing.write"],
      "description": "Mount a shared folder to the user's Dropbox."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/unmount_folder",
      "sufficientScopes": ["sharing.write"],
      "description": "Unmount a shared folder from the user's Dropbox."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/relinquish_folder_membership",
      "sufficientScopes": ["sharing.write"],
      "description": "Leave a shared folder."
    },
    {
      "method": "POST",
      "pathPattern": "/2/sharing/set_access_inheritance",
      "sufficientScopes": ["sharing.write"],
      "description": "Set access inheritance for a shared folder."
    },
    {
      "method": "POST",
